// Dans le store auth, après login :
const mergeWishlistAfterLogin = async (localItems) => {
  const backendItems = await fetch('/api/wishlist').then(res => res.json());
  const mergedItems = [...backendItems];
  localItems.forEach(localItem => {
    if (!mergedItems.some(item => item.id === localItem.id)) {
      mergedItems.push(localItem);
    }
  });
  // Envoyer la liste fusionnée au backend
  await fetch('/api/wishlist/sync', { method: 'POST', body: JSON.stringify(mergedItems) });
  // Mettre à jour le store local
  useWishlistStore.setState({ items: mergedItems });
};
