function useWishlistPromoNotifications() {
  const wishlistItems = useWishlistStore(state => state.items);
  useEffect(() => {
    const checkPromos = async () => {
      const lastCheck = localStorage.getItem('lastPromoCheck') || 0;
      const res = await fetch(`/api/wishlist/promos?since=${lastCheck}`);
      const promos = await res.json();
      promos.forEach(promo => {
        toast.success(`${promo.name} est en promotion : ${promo.oldPrice}€ → ${promo.newPrice}€`);
      });
      localStorage.setItem('lastPromoCheck', Date.now());
    };
    const interval = setInterval(checkPromos, 3600000);
    return () => clearInterval(interval);
  }, [wishlistItems]);
}
